mapper.select:
select la.*, ri.id ri_id, ri.room_number, ai.id ai_id , ai.name ai_name, ai.province_name, ai.city_name, ai.district_name, lt.id lt_id, lt.month_count, lt.unit, pt.id pt_id, pt.name pt_name, pt.pay_month_count, pt.additional_info pt_additional_info from lease_agreement la left join room_info ri on la.room_id = ri.id and ri.is_deleted = 0
and ri.room_number = #{queryVo.roomNumber}
left join apartment_info ai on la.apartment_id = ai.id and ai.is_deleted = 0
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
left join lease_term lt on la.lease_term_id = lt.id and lt.is_deleted = 0 left join payment_type pt on la.payment_type_id = pt.id and pt.is_deleted = 0 where la.is_deleted = 0
and la.apartment_id = #{queryVo.apartmentId}
and la.name like concat('%','#{queryVo.name}','%')
and la.phone like concat('%','#{phone}','%')
